questions.questionText:
다음 C 언어 프로그램의 결과로 옳은 것은?

#include <stdio.h>

main() {
    int a = 3, b = 4, c = 5;
    int r1, r2, r3;
    r1 = a < 4 && b <= 4;
    r2 = a > 3 || b <= 5;
    r3 = !c;
    printf("%d", r1 - r2 + r3);
}

다음 C 언어 프로그램 실행 후, 'c'를 입력하였을 때 출력 결과는?

#include <stdio.h>

main() {
    char ch;
    scanf("%c", &ch);
    switch (ch) {
        case 'a':
            printf("one ");
        case 'b':
            printf("two ");
        case 'c':
            printf("three ");
            break;
        case 'd':
            printf("four ");
            break;
    }
}

다음 C 언어 프로그램에서 밑줄 친 부분(!a && !b)과 동일한 의미를 가지는 것은 무엇인가?

#include <stdio.h>

main() {
    int a, b;
    for (a = 0; a < 2; a++)
        for (b = 0; b < 2; b++)
            printf("%d", !a && !b);
}
